#!/usr/bin/env python3
import time
import os
import sys
import platform
import multiprocessing
import socket
import hashlib

def check_timing_rdtsc():
    samples = []
    iterations = 100

    for _ in range(iterations):
        start = time.perf_counter()
        dummy = 0
        for i in range(1000):
            dummy += i
        end = time.perf_counter()
        samples.append(end - start)

    avg = sum(samples) / len(samples)
    variance = sum((x - avg) ** 2 for x in samples) / len(samples)

    threshold = 0.0001
    suspicious = variance > threshold

    return {
        'test': 'timing_analysis',
        'avg_time': avg,
        'variance': variance,
        'suspicious': suspicious,
        'reason': 'high timing variance' if suspicious else 'normal timing'
    }

def check_accelerated_sleep():
    durations = [2.0, 1.5, 1.0]
    results = []

    for requested in durations:
        start = time.perf_counter()
        time.sleep(requested)
        actual = time.perf_counter() - start

        ratio = actual / requested
        accelerated = ratio < 0.8

        results.append({
            'requested': requested,
            'actual': actual,
            'ratio': ratio,
            'accelerated': accelerated
        })

    suspicious = any(r['accelerated'] for r in results)

    return {
        'test': 'sleep_acceleration',
        'samples': results,
        'suspicious': suspicious,
        'reason': 'sleep acceleration detected' if suspicious else 'normal sleep timing'
    }

def check_system_fingerprint():
    indicators = []
    suspicious_score = 0

    try:
        import psutil
        ram_gb = psutil.virtual_memory().total / (1024 ** 3)
        if ram_gb < 4:
            indicators.append('low_ram_%dGB' % int(ram_gb))
            suspicious_score += 2
    except ImportError:
        ram_gb = 0
        indicators.append('psutil_unavailable')

    cpu_count = multiprocessing.cpu_count()
    if cpu_count <= 2:
        indicators.append('low_cpu_%d' % cpu_count)
        suspicious_score += 1

    username = os.getenv('USER') or os.getenv('USERNAME') or 'unknown'
    sandbox_names = ['sandbox', 'test', 'vmuser', 'vbox', 'analysis', 'malware']
    if any(name in username.lower() for name in sandbox_names):
        indicators.append('suspicious_username_%s' % username)
        suspicious_score += 3

    hostname = socket.gethostname().lower()
    sandbox_hosts = ['sandbox', 'analysis', 'cuckoo', 'virus', 'malware']
    if any(name in hostname for name in sandbox_hosts):
        indicators.append('suspicious_hostname_%s' % hostname)
        suspicious_score += 3

    try:
        import psutil
        total_disk = sum(part.total for part in psutil.disk_partitions()
                        if part.mountpoint == '/')
        disk_gb = total_disk / (1024 ** 3)
        if disk_gb < 80:
            indicators.append('small_disk_%dGB' % int(disk_gb))
            suspicious_score += 2
    except:
        pass

    return {
        'test': 'system_fingerprint',
        'ram_gb': ram_gb,
        'cpu_count': cpu_count,
        'username': username,
        'hostname': hostname,
        'indicators': indicators,
        'score': suspicious_score,
        'suspicious': suspicious_score >= 4,
        'reason': '%d suspicious indicators' % suspicious_score
    }

def check_process_list():
    sandbox_processes = [
        'vmtoolsd', 'vmwareuser', 'vmacthlp', 'vboxservice', 'vboxtray',
        'sandboxiedcomlaunch', 'sandboxierpcss', 'procmon', 'procmon64',
        'wireshark', 'fiddler', 'windbg', 'ollydbg', 'x64dbg', 'immunity',
        'ida', 'ida64', 'idaq', 'idaq64', 'httpanalyzer', 'httpdebugger',
        'charles', 'burp', 'processhacker', 'procexp', 'tcpview'
    ]

    found_processes = []

    try:
        import psutil
        for proc in psutil.process_iter(['name']):
            try:
                proc_name = proc.info['name'].lower()
                for suspicious in sandbox_processes:
                    if suspicious in proc_name:
                        found_processes.append(proc_name)
                        break
            except:
                continue
    except ImportError:
        return {
            'test': 'process_analysis',
            'available': False,
            'reason': 'psutil not available'
        }

    return {
        'test': 'process_analysis',
        'available': True,
        'found': found_processes,
        'suspicious': len(found_processes) > 0,
        'reason': 'found %d suspicious processes' % len(found_processes) if found_processes else 'clean'
    }

def check_human_interaction():
    uptime = 0
    try:
        with open('/proc/uptime', 'r') as f:
            uptime = float(f.read().split()[0])
    except:
        try:
            import psutil
            uptime = time.time() - psutil.boot_time()
        except:
            uptime = 0

    uptime_hours = uptime / 3600.0

    suspicious = uptime_hours < 0.5

    return {
        'test': 'human_interaction',
        'uptime_hours': uptime_hours,
        'suspicious': suspicious,
        'reason': 'very recent boot (%.1fh)' % uptime_hours if suspicious else 'normal uptime'
    }

def classify_environment(results):
    total_suspicious = sum(1 for r in results if r.get('suspicious', False))
    total_tests = len(results)

    if total_suspicious == 0:
        return 'CLEAN', 0
    elif total_suspicious <= 2:
        return 'SUSPICIOUS', (total_suspicious * 100) // total_tests
    else:
        return 'SANDBOX', (total_suspicious * 100) // total_tests

def main():
    print("[*] Sandbox Detection Suite")
    print("=" * 70)

    checks = [
        check_timing_rdtsc,
        check_accelerated_sleep,
        check_system_fingerprint,
        check_process_list,
        check_human_interaction
    ]

    results = []
    for check_func in checks:
        print("\n[*] Running %s..." % check_func.__name__)
        result = check_func()
        results.append(result)

        status = 'SUSPICIOUS' if result.get('suspicious', False) else 'CLEAN'
        print("    [%s] %s: %s" % (status[0], result['test'], result.get('reason', 'no reason')))

        if result['test'] == 'system_fingerprint' and result.get('indicators'):
            for indicator in result['indicators']:
                print("        - %s" % indicator)
        elif result['test'] == 'process_analysis' and result.get('found'):
            for proc in result['found'][:5]:
                print("        - %s" % proc)

    print("\n" + "=" * 70)
    classification, confidence = classify_environment(results)
    print("[*] Environment Classification: %s (confidence: %d%%)" % (classification, confidence))

    return 0

if __name__ == '__main__':
    sys.exit(main())
